var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"어디 처박혀 있다 이제 나타난 거야, 꼬맹이! 손맛 죽이잖아!","JPN":"今までどこに隠れてやがったんだ？　チビっ娘ちゃんよォ！\\n殴り甲斐があるじゃねえか！","ENG":"Where have you been this whole time, you little twit! Beating you up feels amazing!","TWN":"妳怎麼被逼到絕境才出現啊，小鬼！真是太帶勁了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"크으......!","JPN":"くぅ……！","ENG":"Ngh!","TWN":"嗚……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_TIRED"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"수연아, 괜찮아?!","JPN":"キズナ、大丈夫！？","ENG":"Are you alright, Sooyeon?","TWN":"秀妍，沒事吧？！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_TIRED"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"아, 아직...... 아직 버틸 수 있어......","JPN":"ま、まだ……まだ耐えられる……","ENG":"I-I can still... keep fighting...","TWN":"還、還能……還能再撐一會……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"안 돼, 이수연! 그 몸으로 더는 무리야!","JPN":"よせ、カナミ！　その体では無理だ！","ENG":"No, Sooyeon! You really can't go on in that state!","TWN":"不可以，李秀妍！妳的身體已經到極限了！"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"큭!?","JPN":"くっ！？","ENG":"Ugh!","TWN":"唔！？"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"비켜라, 날파리. 감상에 방해돼.","JPN":"どけ、羽虫。鑑賞の邪魔じゃ。","ENG":"Move away, fly. You're blocking my view.","TWN":"滾開，小蒼蠅，妳擋到我的視線了。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"하지만 아무래도 내가 했던 말을 정정해야겠군.","JPN":"しかし、どうやら先ほど言ったことは訂正せねばならぬな。","ENG":"But I suppose I do stand corrected.","TWN":"不過，看來我得更正我剛才說的話才行。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"너희들이 내 발가락 두 개보다는 강한 아이들이란 걸 인정하도록 하마.","JPN":"其方たちが妾の足の指を二本以上\\n使わせるほど強い、ということは認めよう。","ENG":"I admit you are stronger than two of my toes.","TWN":"我承認你們比我的兩根腳趾頭是要強一些。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"그래도...... 이건 예상 이상인데.","JPN":"じゃが……これは想定外じゃのう。","ENG":"Even so... this is well beyond my expectation.","TWN":"但就算這樣……你們還是超出了我的預料。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"저 키 큰 녀석, 필멸자 주제에 저런 힘을 발휘하다니 너무 부자연스러워.","JPN":"あの背の高い奴、定命の者の分際であのような力を\\n発揮するとはあまりにも不自然じゃ。","ENG":"The tall one's power is most uncanny for a mere mortal.","TWN":"那個大個子，明明應該必死無疑的，竟然能發揮這種程度的力量，沒道理呀！"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"네 생각은 어떻지, 시종?","JPN":"僕の考えはどうじゃ？","ENG":"What do you think, my servant?","TWN":"你怎麼看，侍從？"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"황송하게도 제 의견 또한 주인님의 혜안으로 짐작하신 바와 같습니다.","JPN":"恐れながら私の意見もまた、主様のご慧眼によるものと\\nまったく同じでございます。","ENG":"If I may dare say so, my perspective is in concurrence with your most sagacious observation.","TWN":"恕我僭越，我的看法與主人慧眼所見一樣。"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"저 나유빈이라는 자, 이번 세계에서 선택된 대적자인 모양이군요.","JPN":"どうやらあのイチノセ・カオルという者が\\nこの世界で選ばれた敵対者なのでしょう。","ENG":"That Na Yubin fellow must be the Antagonist, the adversary of this world.","TWN":"看來那個叫羅瑜斌的人，就是被這次世界選中的敵對者。"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"하하, 역시! 저런 음침한 녀석을 힐데가 아무 이유 없이 제자 삼았을 리 없지!","JPN":"ハハハ、そうじゃろうとも！　あんな陰気臭い奴を\\nヒルデが何の理由もなく弟子に取ったわけがあるまい！","ENG":"Hah hah, I knew it! Otherwise, Hilde wouldn't take in a miserable fool like that as her apprentice!","TWN":"哈哈，果然！不然希爾德才不會毫無由來地，把那個陰沉的傢伙收為徒弟！"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};